Object data = 42;

// The Java 21+ Pattern Matching Switch:
String result = switch (data) {
    // 1. Is it an Integer greater than 50? (Using a Guard Clause)
    case Integer i when i > 50 -> "High Number: " + i;

    // 2. Is it just a standard Integer?
    case Integer i -> "Low Number: " + i;

    // 3. Is it a String?
    case String s -> "Text detected: " + s;

    // 4. Guaranteed fallback
    default -> "Unknown Data Type";
};

System.out.println(result); // Prints "Low Number: 42"

