import java.util.function.Predicate;

// 1. Store the condition logic inside a variable
Predicate<Integer> isAdult = age -> age >= 18;
Predicate<Integer> isSenior = age -> age >= 65;

int userAge = 21;

// 2. Use the variable's .test() method to trigger the condition
if (isAdult.test(userAge)) {
    System.out.println("User is over 18.");
}

// 3. You can even combine them dynamically!
if (isAdult.and(isSenior.negate()).test(userAge)) {
    System.out.println("Adult, but not yet a senior.");
}

