String userInput = "abc";

// THE TOXIC WAY (Exceptions for Flow):
// Blindly running the code and using the crash as an 'else' block.
try {
    int number = Integer.parseInt(userInput);
    System.out.println("Valid number: " + number);
} catch (NumberFormatException e) {
    System.out.println("Invalid input!");
}

// THE PROFESSIONAL WAY (Regex Pattern Match):
// Use an 'if' statement to check the data safely BEFORE executing!
if (userInput.matches("^[0-9]+$")) {
    int number = Integer.parseInt(userInput);
    System.out.println("Valid number: " + number);
} else {
    System.out.println("Invalid input!");
}

